-				c.Set("Cache-Control", fmt.Sprintf("public, max-age=%d, immutable", oneYear))
+				c.Set("Cache-Control", cacheHeader)
 				c.Set("Content-Length", fmt.Sprintf("%d", brInfo.Size()))
